import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { addCourse } from "../courseReducer";

function AddCourse() {
  const [name, setName] = useState("");
  const [classId, setClassId] = useState("");
  const [file, setFile] = useState(null);
  const [classes, setClasses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data));
  }, []);

  async function handleSubmit(e) {
    e.preventDefault();
    let filePath = null;

    if (file) {
      const allowedTypes = ["image/jpeg", "image/png", "application/pdf"];
      const maxSize = 5 * 1024 * 1024;

      if (!allowedTypes.includes(file.type)) {
        toast.error("Допустимы только изображения (JPEG, PNG) или PDF-файлы");
        return;
      }

      if (file.size > maxSize) {
        toast.error("Файл слишком большой. Максимальный размер: 5 МБ");
        return;
      }

      const formData = new FormData();
      formData.append("file", file);
      try {
        const response = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const data = await response.json();
        if (response.ok) {
          filePath = data.filePath;
        } else {
          toast.error("Не удалось загрузить файл");
          return;
        }
      } catch (error) {
        toast.error("Сетевая ошибка при загрузке файла");
        return;
      }
    }

    // Проверка и создание предмета
    let subjectId;
    try {
      const subjectsResponse = await fetch(`http://localhost:3001/subjects?name=${name}`);
      const subjects = await subjectsResponse.json();

      if (subjects.length > 0) {
        subjectId = subjects[0].id;
      } else {
        const newSubject = { name };
        const subjectResponse = await fetch("http://localhost:3001/subjects", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(newSubject),
        });
        const createdSubject = await subjectResponse.json();
        subjectId = createdSubject.id;
      }

      // Связь учителя и предмета
      const teacherSubject = { teacherId: user.id, subjectId };
      await fetch("http://localhost:3001/teacher_subjects", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(teacherSubject),
      });

      const newCourse = {
        name,
        subjectId,
        teacherId: user.id,
        classId: parseInt(classId),
      };

      const courseResponse = await fetch("http://localhost:3001/courses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newCourse),
      });

      if (courseResponse.ok) {
        const course = await courseResponse.json();
        if (filePath) {
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: course.id,
              filePath,
              fileName: file.name,
            }),
          });
        }
        dispatch(addCourse(course));
        toast.success("Курс успешно добавлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось добавить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при добавлении курса");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Добавить курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">
                    Название курса
                  </label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="class" className="form-label">
                    Класс
                  </label>
                  <select
                    id="class"
                    className="form-select"
                    value={classId}
                    onChange={(e) => setClassId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите класс --</option>
                    {classes.map((cls) => (
                      <option key={cls.id} value={cls.id}>
                        {cls.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">
                    Прикрепить файл (опционально, только JPEG, PNG, PDF, до 5 МБ)
                  </label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">
                  Добавить
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AddCourse;
